export function normalizeLegacySandboxState(sandboxState) {
    if (!sandboxState || typeof sandboxState !== "object") {
        return sandboxState;
    }
    const state = sandboxState;
    const normalizedType = state.type === "hybrid" ? "vercel" : state.type;
    const sandboxName = typeof state.sandboxName === "string" && state.sandboxName.length > 0 ? state.sandboxName : typeof state.sandboxId === "string" && state.sandboxId.length > 0 ? state.sandboxId : undefined;
    if (normalizedType !== "vercel") {
        return sandboxState;
    }
    if (normalizedType === state.type && sandboxName === undefined) {
        return sandboxState;
    }
    const normalizedState = {
        ...state,
        type: normalizedType
    };
    if (sandboxName !== undefined) {
        normalizedState.sandboxName = sandboxName;
        delete normalizedState.sandboxId;
    }
    return normalizedState;
}
function normalizeSessionRecord(session) {
    return {
        ...session,
        sandboxState: normalizeLegacySandboxState(session.sandboxState) ?? null
    };
}
export async function createSession(data) {
    const [session] = await db.insert(sessions).values(data).returning();
    if (!session) {
        throw new Error("Failed to create session");
    }
    return normalizeSessionRecord(session);
}
export async function createSessionWithInitialChat(input) {
    return db.transaction(async (tx)=>{
        const [session] = await tx.insert(sessions).values(input.session).returning();
        if (!session) {
            throw new Error("Failed to create session");
        }
        const [chat] = await tx.insert(chats).values({
            id: input.initialChat.id,
            sessionId: session.id,
            title: input.initialChat.title,
            modelId: input.initialChat.modelId
        }).returning();
        if (!chat) {
            throw new Error("Failed to create chat");
        }
        return {
            session: normalizeSessionRecord(session),
            chat
        };
    });
}
