/**
 * Atomically updates activeStreamId only when the current value matches
 * `expectedStreamId`. Returns true when the update succeeds.
 */ export async function compareAndSetChatActiveStreamId(chatId, expectedStreamId, nextStreamId) {
    const activeStreamMatch = expectedStreamId === null ? isNull(chats.activeStreamId) : eq(chats.activeStreamId, expectedStreamId);
    const [updated] = await db.update(chats).set({
        activeStreamId: nextStreamId
    }).where(and(eq(chats.id, chatId), activeStreamMatch)).returning({
        id: chats.id
    });
    return Boolean(updated);
}
