/**
 * Creates a chat message if it doesn't already exist (idempotent insert).
 * Uses onConflictDoNothing to handle race conditions gracefully.
 * Returns the message if created, or undefined if it already existed.
 */ export async function createChatMessageIfNotExists(data) {
    const [message] = await db.insert(chatMessages).values(data).onConflictDoNothing({
        target: chatMessages.id
    }).returning();
    return message;
}
/**
 * Upserts a chat message - inserts if new, updates parts if already exists.
 * Use this for assistant messages that may have tool results added client-side.
 */ export async function upsertChatMessage(data) {
    const [message] = await db.insert(chatMessages).values(data).onConflictDoUpdate({
        target: chatMessages.id,
        set: {
            parts: data.parts
        }
    }).returning();
    return message;
}
/**
 * Upserts a chat message only when the existing row matches the same chat and role.
 * This prevents accidental overwrite when an ID collision occurs across chats/roles.
 */ export async function upsertChatMessageScoped(data) {
    return db.transaction(async (tx)=>{
        const [inserted] = await tx.insert(chatMessages).values(data).onConflictDoNothing({
            target: chatMessages.id
        }).returning();
        if (inserted) {
            return {
                status: "inserted",
                message: inserted
            };
        }
        const [updated] = await tx.update(chatMessages).set({
            parts: data.parts
        }).where(and(eq(chatMessages.id, data.id), eq(chatMessages.chatId, data.chatId), eq(chatMessages.role, data.role))).returning();
        if (updated) {
            return {
                status: "updated",
                message: updated
            };
        }
        return {
            status: "conflict"
        };
    });
}
