export async function deleteChatMessageAndFollowing(chatId, messageId) {
    return db.transaction(async (tx)=>{
        const orderedMessages = await tx.select({
            id: chatMessages.id,
            role: chatMessages.role
        }).from(chatMessages).where(eq(chatMessages.chatId, chatId)).orderBy(chatMessages.createdAt, chatMessages.id);
        const startIndex = orderedMessages.findIndex((message)=>message.id === messageId);
        if (startIndex < 0) {
            return {
                status: "not_found"
            };
        }
        const targetMessage = orderedMessages[startIndex];
        if (!targetMessage || targetMessage.role !== "user") {
            return {
                status: "not_user_message"
            };
        }
        const idsToDelete = orderedMessages.slice(startIndex).map((message)=>message.id);
        await tx.delete(chatMessages).where(and(eq(chatMessages.chatId, chatId), inArray(chatMessages.id, idsToDelete)));
        const [latestAssistantMessage] = await tx.select({
            createdAt: chatMessages.createdAt
        }).from(chatMessages).where(and(eq(chatMessages.chatId, chatId), eq(chatMessages.role, "assistant"))).orderBy(desc(chatMessages.createdAt), desc(chatMessages.id)).limit(1);
        await tx.update(chats).set({
            lastAssistantMessageAt: latestAssistantMessage?.createdAt ?? null,
            updatedAt: new Date()
        }).where(eq(chats.id, chatId));
        return {
            status: "deleted",
            deletedMessageIds: idsToDelete
        };
    });
}
export async function isFirstChatMessage(chatId, messageId) {
    const rows = await db.select({
        id: chatMessages.id
    }).from(chatMessages).where(eq(chatMessages.chatId, chatId)).orderBy(chatMessages.createdAt, chatMessages.id).limit(2);
    return rows.length === 1 && rows[0]?.id === messageId;
}
export async function markChatRead(data) {
    const now = new Date();
    const [chatRead] = await db.insert(chatReads).values({
        userId: data.userId,
        chatId: data.chatId,
        lastReadAt: now,
        updatedAt: now
    }).onConflictDoUpdate({
        target: [
            chatReads.userId,
            chatReads.chatId
        ],
        set: {
            lastReadAt: now,
            updatedAt: now
        }
    }).returning();
    return chatRead;
}
